INSERT INTO questions (chapter, question, options, correct_answer, explanation, difficulty) VALUES
(1, 'What is the primary goal of NASM''s integrated training approach?', '["Maximize muscle size", "Improve all functional abilities simultaneously", "Focus exclusively on strength", "Train only cardiovascular endurance"]'::jsonb, 1, 'NASM''s integrated training combines flexibility, core, balance, reactive, resistance, and cardio training to improve all functional abilities — not just one area in isolation.', 'easy'),
(1, 'Evidence-based practice in personal training relies on which three components?', '["Cost, availability, popularity", "Scientific evidence, clinical experience, client values", "Equipment, facility, schedule", "Certification, insurance, marketing"]'::jsonb, 1, 'Evidence-based practice integrates the best available scientific evidence with clinical expertise and individual client values/preferences to guide training decisions.', 'medium'),
(1, 'Which of the following best describes the kinetic chain concept?', '["A sequence of exercises in a workout", "The interrelation of the nervous, muscular, and skeletal systems", "A type of resistance training equipment", "The order of energy system activation during exercise"]'::jsonb, 1, 'The human movement system (kinetic chain) describes how the nervous, muscular, and skeletal systems work together interdependently. Dysfunction in one component affects the others.', 'easy'),
(1, 'A personal trainer notices a new research study contradicts their current programming approach. According to evidence-based practice, what should they do?', '["Ignore the study and continue current methods", "Immediately change all client programs", "Evaluate the study quality, consider clinical experience, and adapt as appropriate", "Wait for at least five confirming studies before making changes"]'::jsonb, 2, 'Evidence-based practice requires critically evaluating research quality while integrating it with professional experience and client needs — not blindly following or ignoring any single study.', 'hard'),
(1, 'What does the NASM OPT model stand for?', '["Optimal Power Training", "Optimum Performance Training", "Overhead Press Technique", "Organized Physical Therapy"]'::jsonb, 1, 'The OPT model stands for Optimum Performance Training. It is NASM''s systematic approach to program design that progresses clients through stabilization, strength, and power levels.', 'easy'),
(1, 'Which of the following is the most significant barrier to physical activity in the general population?', '["Lack of equipment", "Perceived lack of time", "Absence of a training partner", "High cost of gym membership"]'::jsonb, 1, 'Research consistently shows that perceived lack of time is the most commonly cited barrier to physical activity. Effective trainers help clients overcome this through efficient programming and scheduling strategies.', 'medium'),
(1, 'What percentage of American adults meet the recommended physical activity guidelines?', '["About 75%", "About 50%", "Less than 25%", "Over 90%"]'::jsonb, 2, 'Fewer than 25% of American adults meet the recommended physical activity guidelines, contributing to the high rates of chronic disease and obesity. This highlights the critical role of fitness professionals.', 'medium'),
(1, 'A client states they want to ''get toned.'' Using evidence-based practice, the trainer should:', '["Design a program using only light weights and high reps", "Clarify the client''s specific goals and design a program based on scientific principles of body composition change", "Tell the client that ''toning'' is not a real fitness concept", "Recommend only cardiovascular exercise"]'::jsonb, 1, 'Evidence-based practice requires understanding client values (their goal of ''toning'') and translating that into a scientifically sound program that addresses body composition through resistance training, cardio, and nutrition guidance.', 'medium'),
(1, 'Which chronic disease is most directly linked to physical inactivity?', '["Skin cancer", "Type 2 diabetes", "Allergies", "Cataracts"]'::jsonb, 1, 'Type 2 diabetes is strongly linked to physical inactivity and poor diet. Regular exercise improves insulin sensitivity and helps manage blood glucose levels.', 'easy'),
(1, 'The integrated training approach differs from traditional training primarily because it:', '["Uses heavier weights", "Addresses multiple components of fitness in each workout", "Eliminates the need for cardiovascular exercise", "Focuses on one muscle group per session"]'::jsonb, 1, 'Integrated training incorporates flexibility, cardiorespiratory, core, balance, reactive, and resistance training into each session, rather than isolating single components as traditional approaches often do.', 'easy'),
(1, 'When a personal trainer encounters a client with a medical condition outside their scope, they should:', '["Attempt to treat the condition with exercise", "Refer the client to an appropriate healthcare professional", "Refuse to train the client entirely", "Research the condition online and proceed independently"]'::jsonb, 1, 'Trainers must recognize the limits of their scope of practice and refer clients to qualified healthcare professionals when medical conditions are present. They can still train the client within their scope after medical clearance.', 'easy'),
(1, 'Which of the following represents a modifiable risk factor for chronic disease?', '["Age", "Gender", "Physical inactivity", "Family history"]'::jsonb, 2, 'Physical inactivity is a modifiable risk factor — it can be changed through behavior. Age, gender, and family history are non-modifiable risk factors that cannot be altered.', 'medium'),
(2, 'Which type of muscle fiber is best suited for endurance activities?', '["Type II (fast-twitch)", "Type I (slow-twitch)", "Type IIx (fast-twitch glycolytic)", "Type III (super fast-twitch)"]'::jsonb, 1, 'Type I (slow-twitch) fibers are fatigue-resistant and well-suited for sustained, endurance-based activities. They use aerobic metabolism primarily.', 'easy'),
(2, 'What is the role of the Golgi tendon organ (GTO)?', '["Detect changes in muscle length", "Sense changes in muscular tension and cause relaxation", "Increase muscle contraction speed", "Store elastic energy"]'::jsonb, 1, 'The GTO is a sensory receptor in tendons that senses changes in muscular tension. When stimulated (like during a sustained stretch), it causes the muscle to relax — this is called autogenic inhibition.', 'medium'),
(2, 'What is the function of a synergist muscle?', '["Oppose the primary mover", "Assist the primary mover in performing a movement", "Stabilize joints not directly involved", "Generate maximum force independently"]'::jsonb, 1, 'A synergist assists the agonist (primary mover) in producing a desired movement. For example, the brachialis is a synergist to the biceps during elbow flexion.', 'easy'),
(2, 'Muscle spindles are sensitive to changes in:', '["Muscular tension", "Muscle length and rate of length change", "Blood pressure within the muscle", "Muscle temperature"]'::jsonb, 1, 'Muscle spindles are proprioceptors located within the muscle belly that detect changes in muscle length and the rate of that change. When a muscle is stretched quickly, muscle spindles trigger the stretch reflex to prevent overstretching.', 'medium'),
(2, 'The three components of the nervous system that control human movement are:', '["Brain, heart, lungs", "Central, peripheral, and autonomic nervous systems", "Sensory, integrating, and motor functions", "Cerebrum, cerebellum, and brainstem"]'::jsonb, 2, 'The nervous system controls movement through three basic functions: sensing (sensory input from the environment), integrating (processing and interpreting the sensory information), and responding (motor output to muscles).', 'medium'),
(2, 'Which connective tissue directly surrounds individual muscle fibers?', '["Epimysium", "Perimysium", "Endomysium", "Fascia"]'::jsonb, 2, 'The endomysium is the innermost layer of connective tissue that surrounds individual muscle fibers. The perimysium surrounds bundles of fibers (fascicles), and the epimysium surrounds the entire muscle.', 'medium'),
(2, 'A client rapidly stretches their hamstring and feels it immediately contract. This response is caused by:', '["The Golgi tendon organ", "The muscle spindle activating the stretch reflex", "Voluntary muscle contraction", "Autogenic inhibition"]'::jsonb, 1, 'The muscle spindle detects rapid changes in muscle length and triggers the stretch reflex (myotatic reflex), causing the muscle to contract to protect itself from being overstretched.', 'hard'),
(2, 'The sliding filament theory describes:', '["How bones glide over each other at joints", "The mechanism of muscular contraction at the sarcomere level", "The movement of fascia during stretching", "How nerve impulses travel along axons"]'::jsonb, 1, 'The sliding filament theory explains how actin and myosin filaments slide past each other within the sarcomere to produce muscle contraction. The filaments don''t shorten themselves — they overlap more.', 'medium'),
(2, 'Which division of the nervous system is responsible for the ''fight or flight'' response?', '["Parasympathetic nervous system", "Somatic nervous system", "Sympathetic nervous system", "Central nervous system"]'::jsonb, 2, 'The sympathetic nervous system activates the fight-or-flight response, increasing heart rate, blood pressure, and energy mobilization. The parasympathetic system promotes rest and recovery.', 'easy'),
(2, 'The point where a motor neuron meets a muscle fiber is called the:', '["Synapse", "Neuromuscular junction", "Motor cortex", "Proprioceptor"]'::jsonb, 1, 'The neuromuscular junction is the specialized synapse where a motor neuron communicates with a muscle fiber, triggering contraction through the release of acetylcholine.', 'easy'),
(2, 'Type II muscle fibers are characterized by:', '["High oxidative capacity and slow contraction speed", "Low force production and high endurance", "High force production and fast contraction speed", "High mitochondrial density and slow fatigue"]'::jsonb, 2, 'Type II (fast-twitch) fibers produce high force, contract quickly, but fatigue faster than Type I fibers. They rely more on anaerobic metabolism and are recruited for powerful, explosive movements.', 'easy'),
(2, 'Autogenic inhibition occurs when:', '["Muscle spindles cause a muscle to contract", "The GTO senses excessive tension and causes the muscle to relax", "An antagonist muscle overrides the agonist", "The brain consciously relaxes a muscle"]'::jsonb, 1, 'Autogenic inhibition is the process by which the GTO, sensing excessive tension in a muscle-tendon unit, causes that same muscle to relax. This protective mechanism is the basis for static stretching and SMR techniques.', 'medium'),
(2, 'A motor unit consists of:', '["A single muscle fiber and all its nuclei", "A motor neuron and all the muscle fibers it innervates", "The entire muscle and its nerve supply", "Two antagonistic muscles working together"]'::jsonb, 1, 'A motor unit is a motor neuron and all the muscle fibers it controls. When the motor neuron fires, all fibers in that motor unit contract simultaneously (all-or-nothing principle).', 'medium'),
(2, 'During a 30-second sustained static stretch, which proprioceptor is primarily responsible for the gradual relaxation felt in the muscle?', '["Muscle spindle", "Golgi tendon organ", "Pacinian corpuscle", "Ruffini ending"]'::jsonb, 1, 'During a sustained stretch, the GTO detects the prolonged tension in the tendon and triggers autogenic inhibition, causing the muscle to relax gradually. This is why holding a stretch for 30 seconds is recommended.', 'hard'),
(3, 'What is the primary function of the cardiorespiratory system?', '["Produce hormones for muscle growth", "Transport oxygen and nutrients to tissues and remove waste products", "Generate body heat exclusively", "Maintain skeletal alignment"]'::jsonb, 1, 'The cardiorespiratory system''s primary function is to deliver oxygen and nutrients to working tissues while removing metabolic waste products like carbon dioxide and lactic acid.', 'easy'),
(3, 'Stroke volume is defined as:', '["The total volume of blood in the body", "The amount of blood pumped per heartbeat", "The number of heartbeats per minute", "The blood pressure during contraction"]'::jsonb, 1, 'Stroke volume is the amount of blood ejected from the left ventricle with each heartbeat. Cardiac output equals stroke volume multiplied by heart rate (Q = SV x HR).', 'easy'),
(3, 'VO2 max represents:', '["The maximum heart rate a person can achieve", "The maximum amount of oxygen the body can use during exercise", "The volume of air in the lungs at rest", "The maximum blood pressure during exercise"]'::jsonb, 1, 'VO2 max is the maximum rate of oxygen consumption during incremental exercise. It is considered the best indicator of cardiorespiratory fitness and aerobic endurance capacity.', 'easy'),
(3, 'As a result of chronic aerobic training, resting heart rate typically:', '["Increases due to cardiac stress", "Remains unchanged", "Decreases because stroke volume increases", "Becomes irregular"]'::jsonb, 2, 'Chronic aerobic training increases stroke volume (the heart pumps more blood per beat), so fewer beats per minute are needed to maintain the same cardiac output at rest, resulting in a lower resting heart rate.', 'medium'),
(3, 'Normal resting blood pressure is classified as:', '["140/90 mmHg", "120/80 mmHg or less", "130/85 mmHg", "100/60 mmHg"]'::jsonb, 1, 'Normal resting blood pressure is classified as systolic less than 120 mmHg and diastolic less than 80 mmHg. Values above 130/80 are now considered hypertensive by current guidelines.', 'easy'),
(3, 'The Valsalva maneuver during resistance training is dangerous primarily because it:', '["Reduces muscle force production", "Causes a dramatic spike in blood pressure", "Decreases oxygen delivery to muscles", "Reduces core stability"]'::jsonb, 1, 'The Valsalva maneuver (holding breath against a closed glottis) causes a dramatic spike in blood pressure, which can be dangerous especially for clients with hypertension or cardiovascular conditions.', 'medium'),
(3, 'Which chamber of the heart pumps oxygenated blood to the body?', '["Right atrium", "Right ventricle", "Left atrium", "Left ventricle"]'::jsonb, 3, 'The left ventricle pumps oxygenated blood through the aorta to the systemic circulation. It has the thickest walls of all four chambers because it must generate enough pressure to push blood throughout the entire body.', 'easy'),
(3, 'During exercise, blood flow is redistributed primarily to:', '["The digestive organs", "The brain only", "Working skeletal muscles", "The kidneys"]'::jsonb, 2, 'During exercise, blood is redirected away from non-essential organs (like the digestive system) to working skeletal muscles, which may receive up to 80-85% of cardiac output during intense exercise.', 'easy'),
(3, 'A client''s resting heart rate is 85 bpm. This is considered:', '["Bradycardic (low)", "Normal", "Elevated/above optimal", "Dangerous and requiring immediate referral"]'::jsonb, 2, 'Normal resting heart rate is 60-100 bpm, but optimal is typically 60-80 bpm. A resting heart rate of 85 bpm, while technically normal, is above optimal and suggests room for improved cardiovascular fitness.', 'medium'),
(3, 'The ventilatory threshold represents the point during exercise where:', '["Breathing rate decreases", "The body shifts from primarily aerobic to anaerobic metabolism", "Heart rate reaches its maximum", "Blood pressure normalizes"]'::jsonb, 1, 'The ventilatory threshold is the point during increasing exercise intensity where ventilation increases disproportionately to oxygen consumption, indicating a shift toward greater anaerobic metabolism and increased lactate production.', 'hard'),
(3, 'Cardiac output is calculated by:', '["Blood pressure x heart rate", "Stroke volume x heart rate", "Tidal volume x respiratory rate", "VO2 max x body weight"]'::jsonb, 1, 'Cardiac output (Q) = Stroke Volume (SV) x Heart Rate (HR). It represents the total volume of blood pumped by the heart per minute and increases during exercise through increases in both SV and HR.', 'medium'),
(3, 'A trained endurance athlete would most likely have which of the following adaptations?', '["Smaller left ventricle and faster resting heart rate", "Larger stroke volume and lower resting heart rate", "Higher resting blood pressure and reduced VO2 max", "Decreased capillary density in muscles"]'::jsonb, 1, 'Chronic endurance training leads to cardiac hypertrophy (larger left ventricle), increased stroke volume, lower resting heart rate, increased capillary density, and higher VO2 max.', 'medium'),
(3, 'The systolic blood pressure reading represents:', '["The pressure when the heart is at rest between beats", "The pressure when the left ventricle contracts", "The average pressure during a full cardiac cycle", "The pressure in the pulmonary arteries"]'::jsonb, 1, 'Systolic pressure is the peak pressure in the arteries during ventricular contraction (systole). Diastolic pressure is the pressure during the relaxation phase (diastole) between beats.', 'easy'),
(4, 'During an overhead squat assessment, the knees moving inward (valgus) indicates:', '["Strong adductors", "Overactive adductors and underactive gluteus medius", "Proper movement mechanics", "Excessive hamstring flexibility"]'::jsonb, 1, 'Knee valgus (knees caving inward) during a squat indicates overactive adductors/IT band and underactive gluteus medius/maximus. This is a common compensation pattern.', 'medium'),
(4, 'What are the five kinetic chain checkpoints observed during movement assessments?', '["Hands, elbows, shoulders, hips, knees", "Feet/ankles, knees, LPHC, shoulders, head", "Wrists, shoulders, spine, hips, feet", "Neck, chest, core, thighs, calves"]'::jsonb, 1, 'The five kinetic chain checkpoints are: feet and ankles, knees, lumbo-pelvic-hip complex (LPHC), shoulders, and head/cervical spine. These are observed from anterior, lateral, and posterior views.', 'medium'),
(4, 'The PAR-Q is used to:', '["Measure maximal strength", "Identify individuals who need medical clearance before exercise", "Determine body fat percentage", "Assess cardiorespiratory endurance"]'::jsonb, 1, 'The Physical Activity Readiness Questionnaire (PAR-Q) is a pre-participation health screening tool that identifies individuals who may have contraindications to exercise and need physician clearance.', 'easy'),
(4, 'During the overhead squat assessment, the arms falling forward indicates:', '["Strong anterior deltoids", "Overactive latissimus dorsi and underactive middle/lower trapezius", "Good shoulder mobility", "Underactive pectorals"]'::jsonb, 1, 'Arms falling forward suggests overactive latissimus dorsi, teres major, and pectorals, with underactive middle and lower trapezius and rhomboids. This indicates poor thoracic spine extension and shoulder mobility.', 'hard'),
(4, 'Which body composition assessment method uses skinfold measurements?', '["Bioelectrical impedance", "Durnin-Womersley method", "Hydrostatic weighing", "DEXA scan"]'::jsonb, 1, 'The Durnin-Womersley method uses skinfold calipers to measure subcutaneous fat at specific body sites. It is a practical and accessible method for personal trainers to estimate body fat percentage.', 'medium'),
(4, 'A client''s feet turn out excessively during the overhead squat. Which muscles are likely overactive?', '["Tibialis anterior and gluteus medius", "Soleus, lateral gastrocnemius, and biceps femoris (short head)", "Adductors and medial hamstrings", "Quadriceps and hip flexors"]'::jsonb, 1, 'Feet turning out indicates overactive soleus, lateral gastrocnemius, and biceps femoris (short head), with underactive medial gastrocnemius, medial hamstrings, gracilis, and popliteus.', 'hard'),
(4, 'The YMCA 3-minute step test is used to assess:', '["Muscular endurance", "Flexibility", "Cardiorespiratory fitness", "Balance"]'::jsonb, 2, 'The YMCA 3-minute step test is a submaximal cardiorespiratory assessment that estimates aerobic fitness by measuring heart rate recovery after stepping on and off a 12-inch bench at a set cadence.', 'easy'),
(4, 'During the overhead squat, an excessive forward lean of the torso most likely indicates:', '["Strong core musculature", "Overactive soleus/gastrocnemius and underactive gluteus maximus/erector spinae", "Tight hamstrings only", "Weak quadriceps only"]'::jsonb, 1, 'An excessive forward lean suggests overactive soleus, gastrocnemius, hip flexors, and abdominals, with underactive gluteus maximus, erector spinae, and anterior tibialis.', 'hard'),
(4, 'What is the recommended order for conducting fitness assessments?', '["Strength tests, cardio tests, flexibility tests", "Health history, resting vitals, body composition, movement assessments, performance tests", "Movement assessments first, then health history", "Any order is equally effective"]'::jsonb, 1, 'The proper assessment order ensures safety: start with health history/PAR-Q, then resting vitals (HR, BP), body composition, postural/movement assessments, and finally performance tests if appropriate.', 'medium'),
(4, 'A client has a resting blood pressure of 142/94 mmHg. The trainer should:', '["Begin a vigorous exercise program to lower it", "Refer the client to their physician before starting exercise", "Ignore it since the client feels fine", "Have the client do only upper body exercises"]'::jsonb, 1, 'A reading of 142/94 mmHg is classified as hypertensive. The trainer should refer the client to a physician for medical clearance before beginning an exercise program. This is outside the trainer''s scope to manage.', 'medium'),
(4, 'The single-leg squat assessment is primarily used to observe:', '["Maximal lower body strength", "Dynamic lower extremity alignment and control", "Hamstring flexibility", "Cardiovascular endurance"]'::jsonb, 1, 'The single-leg squat assesses dynamic lower extremity alignment, looking at the same checkpoints as the overhead squat but with the added challenge of single-leg stability to identify asymmetries.', 'medium'),
(4, 'Waist-to-hip ratio is a measurement used to assess:', '["Muscular endurance", "Body fat distribution and associated health risk", "Cardiovascular fitness", "Flexibility"]'::jsonb, 1, 'Waist-to-hip ratio assesses body fat distribution. A higher ratio (more abdominal fat) is associated with greater risk of cardiovascular disease, diabetes, and metabolic syndrome.', 'easy'),
(5, 'During the lowering phase of a push-up, the chest muscles are performing which type of contraction?', '["Concentric", "Isometric", "Eccentric", "Isokinetic"]'::jsonb, 2, 'During the lowering phase, the chest muscles lengthen under tension to control the descent — this is an eccentric contraction. The pushing-up phase is concentric.', 'easy'),
(5, 'According to the force-velocity curve, what happens as concentric contraction velocity increases?', '["Force production increases", "Force production decreases", "Force stays the same", "Force becomes unpredictable"]'::jsonb, 1, 'The force-velocity relationship shows that as the speed of a concentric contraction increases, the force the muscle can produce decreases. This is why you can lift heavier weights slowly than quickly.', 'hard'),
(5, 'The length-tension relationship states that a muscle generates the greatest force when:', '["It is fully shortened", "It is at its optimal resting length", "It is maximally stretched", "It is in a state of fatigue"]'::jsonb, 1, 'At the optimal resting length, there is the greatest overlap between actin and myosin filaments, allowing maximum cross-bridge formation and therefore maximum force production.', 'medium'),
(5, 'An isometric contraction occurs when:', '["The muscle shortens while producing force", "The muscle lengthens while producing force", "The muscle produces force without changing length", "The muscle relaxes completely"]'::jsonb, 2, 'During an isometric contraction, the muscle produces force but does not change length. An example is holding a plank position or pushing against an immovable wall.', 'easy'),
(5, 'A first-class lever in the human body is exemplified by:', '["A bicep curl (elbow flexion)", "Calf raise (plantar flexion)", "Nodding the head (atlanto-occipital joint)", "Shoulder abduction"]'::jsonb, 2, 'A first-class lever has the fulcrum between the effort and the load. The atlanto-occipital joint (nodding) is an example: the joint is between the neck muscles (effort) and the weight of the face (load).', 'hard'),
(5, 'If a client has a shortened (tight) hip flexor, what effect does this have on the force-couple relationship at the pelvis?', '["It has no effect on pelvic position", "It causes a posterior pelvic tilt", "It causes an anterior pelvic tilt", "It causes lateral pelvic tilt only"]'::jsonb, 2, 'Tight hip flexors pull the front of the pelvis downward, creating an anterior pelvic tilt. This disrupts the force-couple relationship between the hip flexors, glutes, hamstrings, and abdominals.', 'medium'),
(5, 'During a bicep curl, the biceps brachii is the:', '["Antagonist", "Stabilizer", "Agonist", "Synergist"]'::jsonb, 2, 'The agonist (prime mover) is the muscle primarily responsible for producing the desired movement. During a bicep curl, the biceps brachii is the agonist performing elbow flexion.', 'easy'),
(5, 'The rotary component of muscle force is greatest when the angle of pull on the bone is:', '["0 degrees", "45 degrees", "90 degrees", "180 degrees"]'::jsonb, 2, 'The rotary component of muscle force (the component that actually produces joint rotation) is greatest when the muscle pulls at 90 degrees to the bone. At other angles, more force is directed into the joint (stabilizing component) or away from it.', 'hard'),
(5, 'Reciprocal inhibition describes:', '["A muscle relaxing after sustained contraction", "The simultaneous contraction of agonist and antagonist", "The relaxation of an antagonist muscle when the agonist is activated", "The GTO causing a muscle to relax"]'::jsonb, 2, 'Reciprocal inhibition is the process by which activation of a muscle (agonist) causes reflexive relaxation of the opposing muscle (antagonist). For example, when the biceps contracts, the triceps is inhibited.', 'medium'),
(5, 'A client performing a wall sit is primarily using which type of muscle action?', '["Concentric", "Eccentric", "Isometric", "Isokinetic"]'::jsonb, 2, 'During a wall sit, the quadriceps are producing force to hold the position against gravity, but the joint angle is not changing. This is an isometric (same length) contraction.', 'easy'),
(5, 'Synergistic dominance occurs when:', '["The agonist and antagonist contract equally", "A synergist muscle takes over the function of a weak or inhibited prime mover", "Two muscles work together at the same intensity", "The stabilizer muscles become the prime movers in all exercises"]'::jsonb, 1, 'Synergistic dominance occurs when a synergist compensates for a weak or inhibited prime mover. For example, the hamstrings or erector spinae may compensate for an inhibited gluteus maximus during hip extension.', 'medium'),
(5, 'During the eccentric phase of a squat, the quadriceps are:', '["Shortening to push the body up", "Lengthening while controlling the rate of descent", "Completely relaxed", "Contracting isometrically"]'::jsonb, 1, 'During the descent (eccentric phase) of a squat, the quadriceps lengthen under tension to control the rate at which the knees flex and the body lowers. This is a decelerating action.', 'easy'),
(6, 'What is the primary mechanism by which foam rolling (SMR) improves flexibility?', '["Stretching the muscle fibers", "Autogenic inhibition via GTO stimulation", "Increasing blood flow only", "Breaking down scar tissue"]'::jsonb, 1, 'Self-myofascial release (foam rolling) applies sustained pressure to soft tissue, stimulating the GTO which triggers autogenic inhibition — causing the muscle to relax and allowing greater range of motion.', 'medium'),
(6, 'Static stretching is most appropriate during which phase of a workout?', '["Before any warm-up activity", "As the only warm-up method", "After the workout as part of the cool-down", "Between sets of heavy resistance training"]'::jsonb, 2, 'Static stretching is most appropriate during the cool-down phase. Research suggests that static stretching before activity may temporarily reduce power and strength output. It is effective post-workout for improving flexibility.', 'medium'),
(6, 'How long should a static stretch be held for optimal results?', '["5-10 seconds", "15-20 seconds", "30 seconds", "2-3 minutes"]'::jsonb, 2, 'A static stretch should be held for approximately 30 seconds to allow the GTO to override the muscle spindle, triggering autogenic inhibition and allowing the muscle to relax and lengthen.', 'easy'),
(6, 'Active-isolated stretching involves:', '["Holding a stretch for 30+ seconds with no movement", "Using a foam roller on tight muscles", "Using the agonist to actively move the limb through a range of motion, holding for 1-2 seconds", "Bouncing at the end range of motion"]'::jsonb, 2, 'Active-isolated stretching uses reciprocal inhibition by contracting the agonist to move the limb through a range of motion, holding for 1-2 seconds, and repeating for 5-10 reps. This inhibits the antagonist being stretched.', 'medium'),
(6, 'A client who sits at a desk all day is likely to have shortened:', '["Gluteus maximus and hamstrings", "Hip flexors and pectorals", "Rhomboids and middle trapezius", "Posterior deltoids and external rotators"]'::jsonb, 1, 'Prolonged sitting typically leads to shortened (overactive) hip flexors, pectorals, and upper trapezius, with lengthened (underactive) glutes, deep cervical flexors, and mid/lower trapezius.', 'easy'),
(6, 'Dynamic stretching is characterized by:', '["Holding a position for 30 seconds", "Applying pressure with a foam roller", "Using controlled movement through an active range of motion", "Passive partner-assisted stretching"]'::jsonb, 2, 'Dynamic stretching uses active movements to take joints and muscles through their full range of motion in a controlled manner. It is ideal as part of a warm-up to prepare the body for activity.', 'easy'),
(6, 'When foam rolling a tender spot, the client should:', '["Roll quickly back and forth over it", "Avoid the area completely", "Hold pressure on the tender spot for at least 30 seconds", "Only foam roll areas that are not tender"]'::jsonb, 2, 'When a tender spot (trigger point/adhesion) is found during foam rolling, the client should hold sustained pressure on that spot for at least 30 seconds to allow the GTO to relax the tissue.', 'easy'),
(6, 'The corrective flexibility strategy in the OPT model uses which combination?', '["Dynamic stretching and active-isolated stretching", "SMR and static stretching", "Ballistic stretching and PNF stretching", "Active stretching only"]'::jsonb, 1, 'Corrective flexibility (used in Phase 1 Stabilization) combines self-myofascial release (SMR) to inhibit overactive muscles, followed by static stretching to lengthen them. This addresses muscle imbalances.', 'medium'),
(6, 'A client has overactive calves causing their heels to rise during squats. Which flexibility technique combination should be applied first?', '["Dynamic stretching of the calves", "SMR on the calves followed by static calf stretching", "Active-isolated stretching of the tibialis anterior", "Ballistic stretching of the Achilles tendon"]'::jsonb, 1, 'For overactive muscles causing compensation, the corrective strategy is to first foam roll (SMR) the overactive calves to reduce tension via autogenic inhibition, then statically stretch them to improve length.', 'medium'),
(6, 'Which type of flexibility training uses reciprocal inhibition as its primary mechanism?', '["Static stretching", "SMR/foam rolling", "Active-isolated stretching", "Passive stretching"]'::jsonb, 2, 'Active-isolated stretching primarily uses reciprocal inhibition. By actively contracting the agonist (opposing muscle), the antagonist (muscle being stretched) is reflexively relaxed, allowing greater range of motion.', 'hard'),
(6, 'Davis''s Law states that:', '["Muscles only grow when loaded progressively", "Soft tissue remodels along the lines of stress placed upon it", "Flexibility cannot be improved after age 40", "Stretching always reduces injury risk"]'::jsonb, 1, 'Davis''s Law describes how soft tissue (muscles, tendons, ligaments, fascia) remodels according to the stresses and demands placed upon it. This is why consistent flexibility training produces lasting tissue changes.', 'hard'),
(6, 'The active flexibility strategy in the OPT model is appropriate for which training level?', '["Phase 1 — Stabilization", "Phases 2-4 — Strength", "Phase 5 — Power only", "Only for rehabilitation settings"]'::jsonb, 1, 'Active flexibility (SMR combined with active-isolated stretching) is used in Phases 2-4 (Strength Level) of the OPT model. It builds on corrective flexibility by incorporating more active neuromuscular control.', 'medium'),
(7, 'The FITTE factors for cardiorespiratory programming stand for:', '["Force, Intensity, Time, Type, Effort", "Frequency, Intensity, Time, Type, Enjoyment", "Flexibility, Intensity, Tempo, Training, Endurance", "Frequency, Intervals, Threshold, Type, Energy"]'::jsonb, 1, 'FITTE stands for Frequency (how often), Intensity (how hard), Time (duration), Type (mode of exercise), and Enjoyment (client preference). Enjoyment is key for long-term adherence.', 'easy'),
(7, 'In NASM''s Stage I cardiorespiratory training, the primary goal is to:', '["Maximize VO2 max", "Build an aerobic base using steady-state training at moderate intensity", "Perform high-intensity interval training", "Train at anaerobic threshold exclusively"]'::jsonb, 1, 'Stage I focuses on building an aerobic base with steady-state, moderate-intensity cardio (65-75% HRmax). This establishes cardiovascular fitness foundations before introducing higher intensities.', 'medium'),
(7, 'The Talk Test is a simple way to estimate:', '["Maximum heart rate", "Exercise intensity relative to ventilatory threshold", "Resting metabolic rate", "Blood lactate levels"]'::jsonb, 1, 'The Talk Test estimates exercise intensity by whether a person can carry on a conversation. If they can talk comfortably, they are likely below the ventilatory threshold. If they cannot, they have likely exceeded it.', 'easy'),
(7, 'A new client with no exercise history should begin cardio training in which NASM stage?', '["Stage III with interval training", "Stage II with moderate intervals", "Stage I with steady-state training", "Any stage based on client preference"]'::jsonb, 2, 'Beginners should start in Stage I to build an aerobic base with moderate, steady-state cardio. This develops foundational cardiovascular fitness and allows safe progression to higher intensities.', 'easy'),
(7, 'Heart rate reserve (HRR) is calculated by:', '["Maximum heart rate minus age", "Maximum heart rate minus resting heart rate", "Resting heart rate plus age", "VO2 max divided by body weight"]'::jsonb, 1, 'Heart rate reserve = HRmax - HRrest. It represents the range of heart rate available for exercise. The Karvonen formula uses HRR to calculate target heart rate zones that account for individual fitness levels.', 'medium'),
(7, 'Stage II of NASM''s cardiorespiratory training introduces:', '["Steady-state training only", "Interval training with alternating higher and lower intensities", "Maximal sprint intervals", "Only low-intensity recovery sessions"]'::jsonb, 1, 'Stage II introduces interval training, alternating between higher-intensity work intervals and lower-intensity recovery intervals. This begins to challenge the anaerobic system while maintaining an aerobic base.', 'medium'),
(7, 'Using the age-predicted formula, the estimated maximum heart rate for a 40-year-old is:', '["160 bpm", "180 bpm", "200 bpm", "170 bpm"]'::jsonb, 1, 'The age-predicted HRmax formula is 220 - age. For a 40-year-old: 220 - 40 = 180 bpm. This is an estimate with a standard deviation of about 10-12 bpm.', 'easy'),
(7, 'Which of the following is a benefit of high-intensity interval training (HIIT)?', '["It only burns calories during the workout", "It produces excess post-exercise oxygen consumption (EPOC)", "It is safer than moderate-intensity exercise for beginners", "It requires no recovery between sessions"]'::jsonb, 1, 'HIIT produces significant EPOC (the ''afterburn effect''), meaning the body continues to burn additional calories after the workout as it restores itself to homeostasis. However, it requires adequate fitness levels and recovery time.', 'medium'),
(7, 'A client exercising at 60-70% of their HRmax is training in which zone?', '["Zone 1 (recovery)", "Zone 2 (aerobic base/fat burning)", "Zone 3 (anaerobic threshold)", "Zone 4 (near maximal)"]'::jsonb, 1, 'Training at 60-70% HRmax falls in Zone 2, which builds the aerobic base and uses a higher proportion of fat as fuel. This zone is appropriate for building endurance and is sustainable for longer durations.', 'medium'),
(7, 'Stage III of NASM''s cardiorespiratory training is characterized by:', '["Low-intensity steady-state only", "Moderate interval training", "High-intensity interval training pushing near VO2 max", "Exclusively recovery-paced sessions"]'::jsonb, 2, 'Stage III uses high-intensity intervals that push near or at VO2 max with recovery periods. This stage is for well-conditioned clients and aims to maximize cardiorespiratory performance.', 'medium'),
(7, 'A client can speak in full sentences during their cardio workout but with some difficulty. They are likely training:', '["Well below their ventilatory threshold", "Near their first ventilatory threshold", "Above their second ventilatory threshold", "At maximum intensity"]'::jsonb, 1, 'Being able to speak with some difficulty suggests the client is near the first ventilatory threshold — the point where breathing starts to increase disproportionately. This indicates moderate-to-vigorous intensity.', 'hard'),
(8, 'The drawing-in maneuver activates which core muscle?', '["Rectus abdominis", "External obliques", "Transverse abdominis", "Erector spinae"]'::jsonb, 2, 'The drawing-in maneuver (pulling the navel toward the spine) specifically activates the transverse abdominis, the deepest core muscle that acts like a natural weight belt to stabilize the spine.', 'easy'),
(8, 'The local stabilization system of the core includes which of the following muscles?', '["Rectus abdominis and external obliques", "Transverse abdominis, multifidus, and pelvic floor muscles", "Latissimus dorsi and quadratus lumborum", "Hip flexors and gluteus maximus"]'::jsonb, 1, 'The local stabilization system consists of muscles that attach directly to the vertebrae: transverse abdominis, multifidus, internal obliques, pelvic floor, and diaphragm. They provide intersegmental stability.', 'medium'),
(8, 'The bracing maneuver differs from the drawing-in maneuver by:', '["Activating only the rectus abdominis", "Co-contracting the global muscles including the rectus abdominis, obliques, and erector spinae", "Relaxing the core entirely", "Focusing solely on the pelvic floor"]'::jsonb, 1, 'Bracing involves co-contracting the global core muscles (rectus abdominis, external obliques, erector spinae) as if preparing to be punched, creating a rigid cylinder of support. It is used during heavier loading.', 'medium'),
(8, 'Core stabilization exercises in Phase 1 of the OPT model should involve:', '["Heavy loaded movements like barbell squats", "Exercises with little motion through the spine and pelvis", "Fast, explosive rotational movements", "Maximum repetitions of sit-ups and crunches"]'::jsonb, 1, 'Phase 1 core stabilization exercises involve minimal spinal motion to train the core to stabilize and resist forces. Examples include planks, bridges, and ball exercises that challenge stability without excessive movement.', 'easy'),
(8, 'The global stabilization system of the core includes the:', '["Transverse abdominis and multifidus", "Quadratus lumborum, obliques, and hip adductors", "Biceps and triceps", "Diaphragm and pelvic floor only"]'::jsonb, 1, 'The global stabilization system includes muscles that attach from the pelvis to the spine: quadratus lumborum, obliques, and hip adductors. They transfer loads between upper and lower extremities and provide trunk stability.', 'medium'),
(8, 'A client has difficulty maintaining a neutral spine during a plank. The trainer should:', '["Have them hold the plank longer to build endurance", "Regress to a modified plank (knees on ground) and teach the drawing-in maneuver", "Progress them to a side plank for more challenge", "Eliminate core exercises from their program"]'::jsonb, 1, 'When a client cannot maintain proper form, the exercise should be regressed. A modified plank with knees down reduces the demand while allowing the client to learn the drawing-in maneuver and build proper stabilization patterns.', 'easy'),
(8, 'The movement system of the core includes which muscles?', '["Transverse abdominis and internal obliques", "Latissimus dorsi, hip flexors, hamstrings, and quadriceps", "Pelvic floor and diaphragm", "Multifidus and rotatores"]'::jsonb, 1, 'The global movement system includes muscles that attach the spine/pelvis to the extremities: latissimus dorsi, hip flexors, hamstrings, and quadriceps. These muscles are primarily responsible for producing movement.', 'medium'),
(8, 'Core strength exercises in Phase 2-4 of the OPT model progress by:', '["Removing all stabilization demands", "Introducing controlled spinal motion against resistance through a full range of motion", "Only using heavy machines", "Performing core exercises on unstable surfaces at maximal speed"]'::jsonb, 1, 'Core strength training in Phases 2-4 introduces more dynamic movements with controlled spinal motion, such as cable rotations and medicine ball exercises, building on the stabilization foundation from Phase 1.', 'medium'),
(8, 'A weak core can contribute to all of the following EXCEPT:', '["Low back pain", "Knee valgus during squatting", "Improved power transfer between limbs", "Excessive forward lean during overhead squat"]'::jsonb, 2, 'A weak core impairs power transfer between limbs — it does not improve it. A weak core contributes to low back pain, compensations like knee valgus, forward lean, and overall decreased functional performance.', 'easy'),
(8, 'Core power exercises in Phase 5 of the OPT model include:', '["Slow, sustained planks held for 60+ seconds", "Explosive movements like medicine ball throws and rotation chops at high velocity", "Machine-based crunches at heavy loads", "Only isometric exercises with added weight"]'::jsonb, 1, 'Core power exercises involve explosive, high-velocity movements such as medicine ball throws, rotation chops, and slam balls. They train the core to produce and transfer force rapidly.', 'easy'),
(8, 'Which of the following best explains why core training should precede extremity training in a workout?', '["Core muscles need the most warm-up time", "A fatigued core cannot properly stabilize the spine during loaded movements", "Core exercises burn more calories than other exercises", "Core muscles recover faster than extremity muscles"]'::jsonb, 1, 'The core must be activated and ready to stabilize the spine before loading the extremities. Training core early ensures it can function as a stable base during subsequent compound exercises, reducing injury risk.', 'hard'),
(9, 'Balance training primarily improves which physiological system?', '["Cardiovascular system", "Proprioceptive and neuromuscular systems", "Digestive system", "Endocrine system"]'::jsonb, 1, 'Balance training enhances the proprioceptive and neuromuscular systems by challenging the body''s ability to sense its position in space and react to maintain stability. Proprioceptors in joints, muscles, and skin are trained.', 'easy'),
(9, 'Which of the following is a proprioceptor involved in balance?', '["Red blood cells", "Muscle spindles", "Mitochondria", "Motor neurons"]'::jsonb, 1, 'Muscle spindles are proprioceptors that sense changes in muscle length and rate of length change. Along with the GTO, joint receptors, and vestibular system, they provide critical sensory information for maintaining balance.', 'easy'),
(9, 'A client who can easily balance on one leg on a stable surface should be progressed to:', '["Two legs on a stable surface", "One leg on an unstable surface (foam pad, BOSU, etc.)", "Seated exercises only", "Heavy bilateral squats"]'::jsonb, 1, 'Balance progressions move from stable to unstable surfaces: two legs stable, one leg stable, two legs unstable, one leg unstable. Adding an unstable surface increases the proprioceptive demand.', 'easy'),
(9, 'Phase 1 (Stabilization) balance exercises should involve:', '["Dynamic movements with jumping and hopping", "Minimal joint movement while maintaining balance on stable or unstable surfaces", "Heavy loaded single-leg exercises", "Explosive multidirectional movements"]'::jsonb, 1, 'Stabilization balance exercises involve minimal joint motion and focus on maintaining a stable position. Examples include single-leg balance and single-leg balance on a foam pad. This trains the neuromuscular system to stabilize.', 'medium'),
(9, 'The three sensory systems that contribute to balance are:', '["Muscular, skeletal, and cardiovascular", "Visual, vestibular, and somatosensory (proprioceptive)", "Sympathetic, parasympathetic, and somatic", "Auditory, visual, and olfactory"]'::jsonb, 1, 'Balance is maintained through integration of three sensory systems: visual (sight), vestibular (inner ear), and somatosensory/proprioceptive (receptors in muscles, tendons, and joints sensing body position).', 'medium'),
(9, 'Closing the eyes during a single-leg balance exercise primarily challenges which sensory input?', '["It eliminates vestibular input", "It removes visual input, forcing greater reliance on proprioceptive and vestibular systems", "It increases somatosensory input", "It has no effect on balance difficulty"]'::jsonb, 1, 'Closing the eyes removes visual input, forcing the body to rely more heavily on proprioceptive (somatosensory) and vestibular systems to maintain balance. This is an effective progression strategy.', 'medium'),
(9, 'Strength-level balance exercises (Phases 2-4) progress by:', '["Reducing the challenge to make exercises easier", "Adding dynamic movement through a full range of motion while maintaining balance", "Eliminating all unstable surface training", "Only performing bilateral exercises"]'::jsonb, 1, 'Strength-level balance exercises add dynamic movement (like single-leg squats, lunges with reaches) through a full range of motion while maintaining balance. This progresses from the static holds of stabilization level.', 'medium'),
(9, 'A 70-year-old client beginning an exercise program should have balance training prioritized because:', '["Older adults enjoy balance exercises more than strength training", "Fall prevention through improved proprioception and stability is critical for older adults", "Balance training replaces the need for cardiovascular exercise", "Balance training builds more muscle than resistance training"]'::jsonb, 1, 'Falls are a leading cause of injury and death in older adults. Balance training improves proprioception, reaction time, and stability, directly reducing fall risk and maintaining functional independence.', 'easy'),
(9, 'Power-level balance exercises (Phase 5) include:', '["Static single-leg stands held for 60 seconds", "Hopping, bounding, and dynamic stabilization upon landing", "Slow bilateral movements on stable surfaces", "Seated balance exercises only"]'::jsonb, 1, 'Power-level balance exercises involve multiplanar, dynamic movements with controlled landing and stabilization. Examples include single-leg hop to stabilization and box jump-downs with hold.', 'medium'),
(9, 'A client repeatedly loses balance to the right during single-leg stands on their left foot. This most likely indicates:', '["Strong left hip abductors", "Weakness or poor neuromuscular control of the left hip stabilizers (gluteus medius)", "Excessive flexibility in the right ankle", "Overactive left quadriceps"]'::jsonb, 1, 'Falling toward the unsupported side (right) during a left single-leg stand suggests the left hip abductors (primarily gluteus medius) are weak or poorly controlled, as they cannot stabilize the pelvis over the stance leg.', 'hard'),
(9, 'Which of the following is the correct progression for balance training?', '["Unstable surface to stable surface to eyes closed", "Two legs stable, single leg stable, two legs unstable, single leg unstable", "Single leg unstable to two legs stable", "Only train balance on machines"]'::jsonb, 1, 'The correct balance progression reduces the base of support and/or stability: two legs on stable surface, single leg on stable surface, two legs on unstable surface, single leg on unstable surface. Additional progressions include closing eyes or adding movement.', 'easy'),
(10, 'The stretch-shortening cycle consists of which three phases?', '["Warm-up, work, cool-down", "Eccentric (loading), amortization (transition), concentric (unloading)", "Isometric, concentric, eccentric", "Acceleration, deceleration, stabilization"]'::jsonb, 1, 'The stretch-shortening cycle has three phases: eccentric (muscle lengthens and stores elastic energy), amortization (brief transition between eccentric and concentric), and concentric (muscle shortens and releases stored energy).', 'medium'),
(10, 'The amortization phase of the stretch-shortening cycle should be:', '["As long as possible for maximum rest", "As short as possible to maximize power output", "At least 5 seconds", "Eliminated entirely for best results"]'::jsonb, 1, 'The amortization phase should be as short as possible. A prolonged amortization phase allows stored elastic energy to dissipate as heat, reducing the power output of the subsequent concentric phase.', 'medium'),
(10, 'Plyometric training is most closely associated with which phase of the OPT model?', '["Phase 1 — Stabilization Endurance", "Phase 2 — Strength Endurance", "Phase 3 — Muscular Development", "Phase 5 — Power"]'::jsonb, 3, 'Plyometric (reactive) training is a key component of Phase 5 (Power) in the OPT model, designed to develop the ability to produce maximum force in the shortest time possible.', 'easy'),
(10, 'A squat jump is an example of which type of plyometric exercise?', '["Stabilization level", "Strength level", "Power level", "Corrective level"]'::jsonb, 2, 'A squat jump is a power-level plyometric exercise involving a dynamic, explosive movement (jumping) as fast as possible. Stabilization-level exercises involve holding a landing, and strength-level exercises involve controlled repeated jumping.', 'medium'),
(10, 'Which of the following is a stabilization-level reactive training exercise?', '["Box jump with maximum height", "Tuck jump", "Squat jump with hold upon landing", "Depth jump to broad jump"]'::jsonb, 2, 'A squat jump landing and holding the position (stabilization) is a stabilization-level reactive exercise. The emphasis is on landing mechanics and holding a stable position for 3-5 seconds, not explosive power.', 'easy'),
(10, 'Before beginning plyometric training, a client should demonstrate:', '["The ability to bench press their body weight", "Adequate core strength, balance, and joint stability", "A VO2 max above 50 mL/kg/min", "The ability to run a 6-minute mile"]'::jsonb, 1, 'Plyometric training places high demands on the musculoskeletal system. Clients need adequate levels of core strength, balance, and joint stability (typically built in earlier OPT phases) before safely performing plyometrics.', 'easy'),
(10, 'Reactive training exercises at the strength level are characterized by:', '["Landing and holding for 3-5 seconds", "Repeated jumps with controlled speed and moderate intensity", "Maximum effort single jumps", "Slow, controlled lowering movements only"]'::jsonb, 1, 'Strength-level reactive exercises involve dynamic, repeated movements with controlled speed. Examples include squat jumps and tuck jumps performed repetitively with moderate intensity and controlled landing.', 'medium'),
(10, 'During a plyometric box jump, a client lands with their knees collapsing inward. The trainer should:', '["Increase the box height to challenge them more", "Continue the exercise since some compensation is normal", "Regress the exercise and address the knee valgus compensation with corrective strategies", "Add ankle weights to strengthen the legs"]'::jsonb, 2, 'Knee valgus during landing indicates poor neuromuscular control and potential injury risk. The trainer should regress the exercise, address the underlying compensation (overactive adductors, underactive glute med) with corrective exercise, and rebuild proper mechanics.', 'medium'),
(10, 'The primary purpose of plyometric training is to:', '["Increase muscle size (hypertrophy)", "Improve muscular endurance", "Enhance the ability to generate maximum force in minimum time (power)", "Improve cardiovascular endurance"]'::jsonb, 2, 'Plyometric training develops power — the ability to produce maximum force as quickly as possible. It trains the neuromuscular system to utilize the stretch-shortening cycle more efficiently.', 'easy'),
(10, 'A depth jump involves stepping off a box and immediately jumping upon landing. This exercise maximizes power by:', '["Allowing a long rest period between jumps", "Using gravity to increase the eccentric load, storing more elastic energy for a powerful concentric phase", "Reducing the demand on the joints", "Eliminating the need for the amortization phase"]'::jsonb, 1, 'The height of the box increases the eccentric load upon landing (more gravitational force). This stores more elastic energy in the muscles and tendons, which is rapidly released during the subsequent jump if the amortization phase is kept short.', 'hard'),
(10, 'Which of the following best describes the progression of reactive training across OPT levels?', '["Power exercises first, then strength, then stabilization", "Stabilization (land and hold), strength (repeated jumps), power (explosive maximum effort)", "All levels use the same exercises at different speeds", "Reactive training only occurs in Phase 5"]'::jsonb, 1, 'Reactive training progresses from stabilization (land and hold for 3-5 seconds), to strength (repeated controlled jumps), to power (explosive, maximum-effort jumps). Each level builds on the neuromuscular control of the previous.', 'medium'),
(10, 'A client performing ice skaters (lateral bounding) is training reactive ability primarily in which plane of motion?', '["Sagittal plane", "Frontal plane", "Transverse plane", "All planes equally"]'::jsonb, 1, 'Ice skaters (lateral bounds) involve side-to-side movement, which occurs primarily in the frontal (coronal) plane. This trains lateral reactive power and is important for sports involving cutting and lateral movement.', 'medium'),
(12, 'In OPT Phase 1 (Stabilization Endurance), what is the recommended rep range?', '["1-5 reps", "6-10 reps", "12-20 reps", "25-30 reps"]'::jsonb, 2, 'Phase 1 uses 12-20 reps with low intensity and a slow tempo (4/2/1) to build muscular endurance and stabilization. The focus is on proper form and neuromuscular control, not heavy loads.', 'easy'),
(12, 'What tempo is recommended for Phase 1 (Stabilization Endurance) exercises?', '["1/0/1 (fast)", "2/0/2 (moderate)", "4/2/1 (slow eccentric)", "X/0/X (explosive)"]'::jsonb, 2, 'Phase 1 uses a 4/2/1 tempo: 4-second eccentric, 2-second isometric hold, 1-second concentric. The slow eccentric phase increases time under tension and demands more stabilization.', 'medium'),
(12, 'A client who can perform 20 push-ups easily but shows poor scapular stability should start in which OPT phase?', '["Phase 2 — Strength Endurance", "Phase 3 — Muscular Development", "Phase 1 — Stabilization Endurance", "Phase 4 — Maximal Strength"]'::jsonb, 2, 'Regardless of strength levels, any client showing movement compensations or stability issues should start in Phase 1 to correct imbalances before progressing. Strength without stability leads to injury.', 'medium'),
(13, 'The OPT model consists of how many phases across how many levels?', '["3 phases, 2 levels", "5 phases, 3 levels", "4 phases, 4 levels", "6 phases, 3 levels"]'::jsonb, 1, 'The OPT model has 5 phases across 3 levels: Level 1 (Stabilization) = Phase 1, Level 2 (Strength) = Phases 2-4, Level 3 (Power) = Phase 5.', 'easy'),
(14, 'How many calories does one gram of fat provide?', '["4 calories", "7 calories", "9 calories", "11 calories"]'::jsonb, 2, 'Fat provides 9 calories per gram — more than double that of carbohydrates (4 cal/g) or protein (4 cal/g). This is why fat is the most calorie-dense macronutrient.', 'easy'),
(14, 'Which component accounts for the largest portion of total daily energy expenditure (TDEE)?', '["Physical activity", "Thermic effect of food", "Basal metabolic rate (BMR)", "Non-exercise activity thermogenesis"]'::jsonb, 2, 'BMR accounts for approximately 70% of total daily energy expenditure. Physical activity accounts for ~20% and the thermic effect of food for ~10%.', 'medium'),
(17, 'For older adult clients, which training consideration is most important?', '["Maximize heavy lifting immediately", "Emphasize balance, stability, and functional movements", "Focus only on cardiovascular training", "Skip warm-ups to save time"]'::jsonb, 1, 'Older adults benefit most from programs emphasizing balance, stability, and functional movements that support activities of daily living and reduce fall risk. Always start with Phase 1 principles.', 'easy'),
(19, 'Which of the following is outside the scope of practice for a personal trainer?', '["Creating exercise programs", "Providing general nutrition information", "Diagnosing a client''s knee pain", "Performing fitness assessments"]'::jsonb, 2, 'Personal trainers cannot diagnose injuries or medical conditions — that''s the scope of licensed medical professionals. Trainers can refer clients to appropriate healthcare providers when needed.', 'easy'),
(19, 'What is the purpose of the PAR-Q questionnaire?', '["Measure body composition", "Screen for potential health risks before exercise", "Assess cardiovascular fitness", "Determine training experience level"]'::jsonb, 1, 'The Physical Activity Readiness Questionnaire (PAR-Q) is a pre-participation screening tool that identifies individuals who may need medical clearance before starting an exercise program.', 'easy'),
(11, 'What is the primary goal of speed, agility, and quickness (SAQ) training?', '["Increase maximal strength", "Improve the rate of force production and neuromuscular efficiency", "Build muscular hypertrophy", "Reduce body fat percentage"]'::jsonb, 1, 'SAQ training is designed to improve the rate of force production and neuromuscular efficiency, enhancing the body''s ability to react and move quickly in all planes of motion.', 'easy'),
(11, 'A client performing cone drills with rapid changes of direction at various angles is primarily training which component?', '["Speed", "Quickness", "Agility", "Muscular endurance"]'::jsonb, 2, 'Agility is the ability to accelerate, decelerate, stabilize, and change direction quickly while maintaining proper posture. Cone drills with directional changes are a classic agility exercise.', 'medium'),
(11, 'Which drill is most appropriate for improving quickness?', '["400-meter sprint", "Pro agility shuttle", "Dot drill", "Tempo run"]'::jsonb, 2, 'Quickness refers to the ability to react and change body position with maximal rate of force production. Dot drills emphasize rapid foot movements and reaction time, making them ideal for quickness training.', 'medium'),
(11, 'In the OPT model, at which phase should a trainer first introduce SAQ drills?', '["Phase 1 only", "Phase 2 and above", "Phase 5 only", "SAQ can be incorporated at all phases with appropriate progressions"]'::jsonb, 3, 'SAQ training can be incorporated at all OPT model phases. In Phase 1, drills focus on stabilization with low intensity, while higher phases use more complex, reactive drills with greater intensity.', 'hard'),
(11, 'A ladder drill where a client must react to a verbal command to change footwork pattern is training:', '["Straight-line speed", "Reactive agility", "Maximal strength", "Flexibility"]'::jsonb, 1, 'Reactive agility involves responding to an unpredictable stimulus (like a verbal cue) while performing movement drills. This trains both cognitive processing and physical agility simultaneously.', 'medium'),
(11, 'Stride length and stride frequency are the two primary components of:', '["Agility", "Quickness", "Speed", "Balance"]'::jsonb, 2, 'Speed is determined by stride length (distance covered per step) and stride frequency (rate of steps). Improving either or both will increase overall speed.', 'easy'),
(11, 'Which of the following is NOT a recommended progression for SAQ training?', '["Moving from stable to unstable surfaces", "Increasing complexity of drills", "Performing SAQ drills in a fatigued state to build toughness", "Adding sport-specific movement patterns"]'::jsonb, 2, 'SAQ drills should be performed when the client is fresh and not fatigued, typically early in the workout after the warm-up. Fatigue compromises form, neuromuscular efficiency, and increases injury risk.', 'hard'),
(11, 'What type of base drill would be most appropriate for a Phase 1 (Stabilization Endurance) client?', '["Reactive box jumps", "Tuck jumps for height", "Lateral shuffles at controlled tempo", "Barbell power cleans"]'::jsonb, 2, 'In Phase 1, SAQ drills should be low intensity with controlled tempos to develop movement quality and stabilization. Lateral shuffles at a controlled tempo build foundational movement patterns safely.', 'medium'),
(11, 'During a speed drill, a client consistently has excessive forward lean and limited arm drive. What should the trainer address first?', '["Have the client sprint faster to build momentum", "Add weighted sprints to increase force output", "Correct running mechanics by cueing upright posture and coordinated arm swing", "Switch to agility training instead"]'::jsonb, 2, 'Proper running mechanics are foundational for speed development. Excessive forward lean and poor arm drive are form issues that should be corrected with technique coaching before increasing intensity.', 'medium'),
(11, 'The backpedal is classified as a drill for which component of SAQ?', '["Speed only", "Quickness only", "Agility", "Flexibility"]'::jsonb, 2, 'The backpedal is an agility drill because it involves deceleration, body control, and the ability to transition to other movements. It trains multi-directional movement competency.', 'easy'),
(12, 'Which acute variable refers to the speed at which each repetition is performed?', '["Training intensity", "Rest interval", "Repetition tempo", "Training volume"]'::jsonb, 2, 'Repetition tempo is the speed at which a repetition is performed, typically expressed as a four-digit code (e.g., 4/2/1 for eccentric/isometric/concentric phases). It directly affects time under tension.', 'easy'),
(12, 'A personal trainer designs a workout using 3 sets of 12 reps at 70% 1RM with 60 seconds rest. Which acute variable was NOT mentioned?', '["Sets", "Repetitions", "Intensity", "Tempo"]'::jsonb, 3, 'The workout describes sets (3), reps (12), intensity (70% 1RM), and rest intervals (60 seconds). Tempo (the speed of each repetition) was not specified in this program design.', 'medium'),
(12, 'Training volume is calculated by:', '["Sets x reps", "Sets x reps x weight", "Weight x rest period", "Reps x tempo"]'::jsonb, 1, 'Training volume is calculated as sets multiplied by repetitions multiplied by weight (load). This provides a measure of total work performed during a training session.', 'easy'),
(12, 'A client who can perform 10 reps of bench press at 150 lbs but fails at the 11th rep is working at approximately what percentage of their 1RM?', '["65%", "75%", "85%", "95%"]'::jsonb, 1, 'According to the repetition-percentage chart, 10 repetitions corresponds to approximately 75% of 1RM. This relationship helps trainers prescribe appropriate loads without direct 1RM testing.', 'medium'),
(12, 'Which training system involves performing two exercises back-to-back for opposing muscle groups with no rest between them?', '["Drop set", "Superset", "Circuit training", "Pyramid"]'::jsonb, 1, 'A superset involves performing two exercises back-to-back with minimal rest, typically targeting opposing muscle groups (e.g., biceps curl followed immediately by triceps extension).', 'easy'),
(12, 'A peripheral heart action (PHA) training system is best described as:', '["Performing only upper body exercises", "Alternating upper and lower body exercises in a circuit to maximize blood flow", "Resting 3-5 minutes between every set", "Training one body part per day"]'::jsonb, 1, 'PHA training alternates upper and lower body exercises in a circuit format, forcing blood to be distributed throughout the body. This maximizes caloric expenditure and cardiovascular demand.', 'hard'),
(12, 'Which resistance training system uses a progressively heavier load while decreasing reps across sets?', '["Drop set", "Circuit training", "Ascending pyramid", "Superset"]'::jsonb, 2, 'An ascending pyramid involves increasing the weight and decreasing the repetitions with each successive set (e.g., set 1: 12 reps at 65%, set 2: 10 reps at 75%, set 3: 8 reps at 85%).', 'medium'),
(12, 'What is the recommended rest interval for a client training for maximal strength?', '["0-30 seconds", "30-60 seconds", "1-2 minutes", "3-5 minutes"]'::jsonb, 3, 'Maximal strength training requires rest intervals of 3-5 minutes to allow the phosphagen (ATP-PC) energy system to fully recover, enabling the client to maintain high force output across sets.', 'medium'),
(12, 'A drop set is performed by:', '["Increasing weight after each set", "Performing a set to failure, then immediately reducing weight and continuing reps", "Alternating between two exercises", "Performing only eccentric contractions"]'::jsonb, 1, 'A drop set involves performing an exercise to failure, then immediately reducing the weight and continuing to perform repetitions. This extends the set beyond normal failure to increase metabolic stress.', 'easy'),
(12, 'A client new to resistance training should begin with which type of exercises?', '["Olympic lifts with maximal loads", "Isolation exercises with heavy resistance", "Machine-based and stabilization exercises at lower intensities", "Plyometric supersets"]'::jsonb, 2, 'New clients should begin with machine-based and stabilization exercises at lower intensities to develop proper movement patterns, neuromuscular control, and connective tissue tolerance before progressing to more complex movements.', 'easy'),
(12, 'If a client''s goal is muscular hypertrophy, which rep range and rest interval combination is most appropriate?', '["1-5 reps, 3-5 minutes rest", "6-12 reps, 60-90 seconds rest", "15-25 reps, 0-30 seconds rest", "1-3 reps, 5-7 minutes rest"]'::jsonb, 1, 'Hypertrophy is best achieved with moderate repetitions (6-12) and moderate rest intervals (60-90 seconds), which optimize metabolic stress and mechanical tension for muscle growth.', 'medium'),
(13, 'Phase 1 of the OPT model is called:', '["Strength Endurance", "Stabilization Endurance", "Muscular Development", "Power"]'::jsonb, 1, 'Phase 1 of the OPT (Optimum Performance Training) model is Stabilization Endurance, which focuses on improving muscular endurance, stability, flexibility, and neuromuscular efficiency.', 'easy'),
(13, 'Which phases of the OPT model make up the Strength level?', '["Phases 1 and 2", "Phases 2, 3, and 4", "Phases 3, 4, and 5", "Phases 1 through 5"]'::jsonb, 1, 'The Strength level includes Phase 2 (Strength Endurance), Phase 3 (Muscular Development/Hypertrophy), and Phase 4 (Maximal Strength). Each progressively increases intensity and load.', 'medium'),
(13, 'A client performing a chest press on a stability ball followed immediately by a barbell bench press is using which OPT phase training strategy?', '["Phase 1 — Stabilization Endurance", "Phase 2 — Strength Endurance", "Phase 3 — Hypertrophy", "Phase 5 — Power"]'::jsonb, 1, 'Phase 2 (Strength Endurance) uses a superset strategy pairing a stabilization exercise with a strength exercise. A stability ball chest press (stabilization) followed by barbell bench press (strength) is a classic Phase 2 approach.', 'hard'),
(13, 'What is the recommended rep range for Phase 3 (Muscular Development/Hypertrophy)?', '["12-20 reps", "6-12 reps", "1-5 reps", "15-25 reps"]'::jsonb, 1, 'Phase 3 (Muscular Development) prescribes 6-12 repetitions at 75-85% of 1RM to maximize mechanical tension and metabolic stress, the primary drivers of hypertrophy.', 'easy'),
(13, 'Periodization in the OPT model refers to:', '["Training only during certain times of the year", "A systematic approach to varying training variables over time to prevent plateaus", "Alternating between cardio and resistance training days", "Performing the same workout every session for consistency"]'::jsonb, 1, 'Periodization is the systematic variation of acute training variables (intensity, volume, rest, tempo) over specific time periods to optimize adaptations and prevent overtraining or plateaus.', 'easy'),
(13, 'A competitive athlete preparing for a season would most benefit from training through which OPT model phase?', '["Phase 1 only", "Phase 3 only", "Phase 5 — Power", "Phase 2 only"]'::jsonb, 2, 'Phase 5 (Power) trains the neuromuscular system to produce the greatest force in the shortest time. This is most beneficial for competitive athletes who need explosive power for sport performance.', 'medium'),
(13, 'In Phase 5 (Power), the recommended tempo for power exercises is:', '["4/2/1 (slow eccentric, pause, slow concentric)", "3/1/3 (moderate across all phases)", "Explosive as fast as can be controlled", "10/5/5 (very slow tempo)"]'::jsonb, 2, 'Phase 5 power exercises use an explosive tempo to maximize rate of force production. The concentric phase should be performed as fast as can be controlled while maintaining proper form.', 'medium'),
(13, 'A mesocycle in periodization typically lasts:', '["1 day", "1 week", "2-6 weeks", "1 year"]'::jsonb, 2, 'A mesocycle typically lasts 2-6 weeks and represents one phase or block of training. Multiple mesocycles make up a macrocycle (the entire training plan, often spanning months to a year).', 'medium'),
(13, 'The acute variables for Phase 1 (Stabilization Endurance) include:', '["1-5 reps, 3-5 min rest, 85-100% intensity", "12-20 reps, 0-90 sec rest, 50-70% intensity", "6-12 reps, 60-90 sec rest, 75-85% intensity", "8-12 reps, 2-4 min rest, 80-90% intensity"]'::jsonb, 1, 'Phase 1 uses high reps (12-20), short rest periods (0-90 seconds), and low to moderate intensity (50-70% 1RM) to develop muscular endurance, proprioception, and joint stability.', 'medium'),
(13, 'Which OPT phase uses the heaviest loads relative to 1RM?', '["Phase 1", "Phase 2", "Phase 3", "Phase 4"]'::jsonb, 3, 'Phase 4 (Maximal Strength) uses the heaviest loads, typically 85-100% of 1RM with 1-5 reps, to recruit the highest threshold motor units and maximize force production.', 'easy'),
(13, 'A personal trainer transitions a client from Phase 2 back to Phase 1 after a two-week vacation. This is an example of:', '["Linear periodization failure", "Undulating periodization", "Appropriate regression based on the client''s current status", "Poor program design"]'::jsonb, 2, 'Returning to Phase 1 after a training break is appropriate regression. After time off, clients lose some neuromuscular adaptations and need to re-establish stabilization and movement quality before progressing again.', 'hard'),
(14, 'How many calories are in one gram of protein?', '["2 calories", "4 calories", "7 calories", "9 calories"]'::jsonb, 1, 'Protein provides 4 calories per gram. For reference, carbohydrates also provide 4 cal/g, fat provides 9 cal/g, and alcohol provides 7 cal/g.', 'easy'),
(14, 'A client weighing 180 lbs wants to consume 1 gram of protein per pound of body weight. How many calories from protein will they consume daily?', '["180 calories", "540 calories", "720 calories", "1620 calories"]'::jsonb, 2, '180 lbs x 1 g/lb = 180 g protein. At 4 calories per gram, 180 g x 4 = 720 calories from protein daily.', 'medium'),
(14, 'Which macronutrient provides the most calories per gram?', '["Protein", "Carbohydrate", "Fat", "Fiber"]'::jsonb, 2, 'Fat provides 9 calories per gram, making it the most calorie-dense macronutrient. Protein and carbohydrates each provide 4 calories per gram.', 'easy'),
(14, 'The glycemic index (GI) measures:', '["Total calories in a food", "How quickly a food raises blood sugar levels", "The protein content of a food", "How much fat a food contains"]'::jsonb, 1, 'The glycemic index measures how quickly a carbohydrate-containing food raises blood glucose levels compared to a reference food (usually pure glucose). High-GI foods cause rapid blood sugar spikes.', 'easy'),
(14, 'A client reports feeling dizzy and having dark-colored urine during a workout. What should the trainer suspect first?', '["Overtraining syndrome", "Dehydration", "Hypoglycemia", "Iron deficiency"]'::jsonb, 1, 'Dark-colored urine and dizziness during exercise are classic signs of dehydration. The trainer should stop exercise, have the client hydrate, and monitor symptoms before continuing.', 'medium'),
(14, 'What is the general recommended daily water intake guideline for active individuals?', '["2-4 cups per day", "Approximately half their body weight in ounces", "1 gallon regardless of body size", "Only when thirsty"]'::jsonb, 1, 'A general guideline is to consume approximately half of body weight (in pounds) in ounces of water daily. Active individuals and those in hot climates may need more.', 'medium'),
(14, 'Which of the following is a function of carbohydrates in the body?', '["Primary building block for muscle tissue", "Preferred energy source for the brain and high-intensity exercise", "Primary structural component of cell membranes", "Production of bile acids"]'::jsonb, 1, 'Carbohydrates are the body''s preferred energy source, especially for the brain and during high-intensity exercise. They are stored as glycogen in muscles and the liver.', 'easy'),
(14, 'A personal trainer should refer a client to a registered dietitian when:', '["The client asks about general healthy eating", "The client has a diagnosed medical condition requiring a specific diet plan", "The client wants to know about pre-workout meals", "The client asks about hydration strategies"]'::jsonb, 1, 'Personal trainers should refer clients to registered dietitians when medical nutrition therapy is needed, such as for diabetes, eating disorders, kidney disease, or other conditions requiring specific dietary prescriptions.', 'medium'),
(14, 'To lose approximately one pound of body fat per week, a client must create a weekly caloric deficit of approximately:', '["1,000 calories", "2,000 calories", "3,500 calories", "5,000 calories"]'::jsonb, 2, 'One pound of body fat contains approximately 3,500 calories. A deficit of 500 calories per day (500 x 7 = 3,500) results in roughly one pound of fat loss per week.', 'easy'),
(14, 'A food with a glycemic index below 55 is considered:', '["High glycemic", "Moderate glycemic", "Low glycemic", "Zero glycemic"]'::jsonb, 2, 'Foods with a GI below 55 are classified as low glycemic. They produce a slower, more gradual rise in blood sugar. Examples include most vegetables, legumes, and whole grains.', 'medium'),
(14, 'Trans fats are associated with increased risk of:', '["Improved cholesterol levels", "Heart disease and elevated LDL cholesterol", "Better insulin sensitivity", "Enhanced recovery from exercise"]'::jsonb, 1, 'Trans fats raise LDL (bad) cholesterol, lower HDL (good) cholesterol, and increase the risk of heart disease, stroke, and type 2 diabetes. They should be minimized or eliminated from the diet.', 'easy'),
(15, 'Which supplement has the most scientific evidence supporting its effectiveness for increasing strength and power?', '["Branched-chain amino acids (BCAAs)", "Creatine monohydrate", "Glutamine", "Conjugated linoleic acid (CLA)"]'::jsonb, 1, 'Creatine monohydrate is the most extensively researched and evidence-supported supplement for increasing strength, power, and lean body mass. It works by increasing phosphocreatine stores in muscle.', 'easy'),
(15, 'An ergogenic aid is defined as:', '["A prescription medication for athletes", "Any substance or method that enhances performance", "A supplement only sold in health food stores", "A banned substance in sports"]'::jsonb, 1, 'An ergogenic aid is any substance, device, or practice that enhances energy use, production, or recovery to improve performance. They can be nutritional, pharmacological, physiological, or psychological.', 'easy'),
(15, 'A client asks about taking a fat-burning supplement. The trainer''s BEST response is:', '["Recommend the most popular brand", "Explain that supplements are not regulated the same as drugs and results vary; suggest focusing on nutrition and exercise first", "Tell them all supplements are unsafe", "Prescribe a specific dosage protocol"]'::jsonb, 1, 'Trainers should educate clients that supplements are not regulated as strictly as pharmaceuticals by the FDA. The foundation of any body composition change should be proper nutrition and consistent exercise.', 'medium'),
(15, 'Which of the following is TRUE about dietary supplements in the United States?', '["The FDA must approve them before they are sold", "They are regulated under DSHEA and do not require pre-market approval", "They must contain exactly what is listed on the label", "They undergo clinical trials like prescription drugs"]'::jsonb, 1, 'Under the Dietary Supplement Health and Education Act (DSHEA) of 1994, supplements do not require FDA pre-market approval. Manufacturers are responsible for safety and labeling, but oversight is limited.', 'medium'),
(15, 'Caffeine is classified as which type of ergogenic aid?', '["Mechanical", "Psychological only", "Pharmacological/nutritional", "Physiological"]'::jsonb, 2, 'Caffeine is a pharmacological/nutritional ergogenic aid. It has been shown to improve endurance performance, increase alertness, and reduce perceived exertion during exercise.', 'medium'),
(15, 'A client is taking a supplement that lists a ''proprietary blend'' on the label. This means:', '["The exact amounts of each ingredient are clearly listed", "The individual ingredient amounts are not disclosed", "The product has been FDA-approved", "It contains no active ingredients"]'::jsonb, 1, 'A proprietary blend lists the ingredients but does not disclose the specific amount of each individual ingredient. This makes it difficult to evaluate effectiveness or safety of the product.', 'medium'),
(15, 'Which third-party certification helps verify that a supplement contains what its label claims?', '["OSHA certification", "NSF Certified for Sport or Informed Sport", "HIPAA compliance", "ADA approval"]'::jsonb, 1, 'NSF Certified for Sport and Informed Sport are third-party testing programs that verify supplements contain what they claim, are free of banned substances, and meet quality standards.', 'medium'),
(15, 'Whey protein is considered a ''fast-digesting'' protein because:', '["It is made from plants", "It is rapidly absorbed by the body, causing a quick rise in amino acids", "It takes 8 hours to digest", "It contains no essential amino acids"]'::jsonb, 1, 'Whey protein is rapidly digested and absorbed, causing a quick spike in blood amino acid levels. This makes it popular for post-workout consumption to support muscle protein synthesis.', 'easy'),
(15, 'A personal trainer should NEVER:', '["Discuss general supplement information with clients", "Recommend a client speak with their doctor about supplements", "Prescribe or diagnose supplement needs for medical conditions", "Share evidence-based research about common supplements"]'::jsonb, 2, 'Personal trainers must not prescribe supplements for medical conditions or diagnose deficiencies, as this falls outside their scope of practice. They can share general information and refer clients to qualified healthcare professionals.', 'easy'),
(15, 'Beta-alanine supplementation is most associated with:', '["Increased maximal strength", "Buffering lactic acid to delay fatigue during high-intensity exercise", "Improved flexibility", "Reduced inflammation"]'::jsonb, 1, 'Beta-alanine increases intramuscular carnosine levels, which buffers hydrogen ions produced during high-intensity exercise. This can delay the onset of muscular fatigue and improve performance in activities lasting 1-4 minutes.', 'hard'),
(16, 'According to the Transtheoretical Model, a client who is exercising regularly but has been doing so for less than 6 months is in which stage of change?', '["Preparation", "Action", "Maintenance", "Contemplation"]'::jsonb, 1, 'The Action stage is when an individual has been actively engaging in the new behavior (regular exercise) for less than 6 months. After 6 months of consistent behavior, they move to the Maintenance stage.', 'medium'),
(16, 'A SMART goal must be all of the following EXCEPT:', '["Specific", "Measurable", "Aggressive", "Time-bound"]'::jsonb, 2, 'SMART goals are Specific, Measurable, Attainable, Realistic, and Time-bound. ''Aggressive'' is not a SMART component. Goals should be challenging yet achievable, not recklessly ambitious.', 'easy'),
(16, 'A client says, ''I know I should exercise, but I just don''t have time.'' This client is most likely in which stage of change?', '["Precontemplation", "Contemplation", "Preparation", "Action"]'::jsonb, 1, 'The Contemplation stage is characterized by awareness that a problem exists and thinking about making a change, but not yet committing. The client acknowledges exercise is important but identifies barriers.', 'medium'),
(16, 'Which motivational interviewing technique involves the trainer restating what the client has said to show understanding?', '["Open-ended questioning", "Reflective listening", "Summarizing", "Affirmation"]'::jsonb, 1, 'Reflective listening involves restating or paraphrasing the client''s words to demonstrate understanding and empathy. It helps build rapport and encourages the client to elaborate on their thoughts and feelings.', 'easy'),
(16, 'Self-efficacy refers to:', '["A client''s actual physical abilities", "A client''s belief in their own ability to succeed in a specific situation", "A trainer''s confidence in their programming", "The number of sessions completed"]'::jsonb, 1, 'Self-efficacy is an individual''s belief in their capacity to execute behaviors necessary to produce specific outcomes. High self-efficacy increases motivation, effort, and persistence with exercise.', 'easy'),
(16, 'A client in the Precontemplation stage would BEST be supported by:', '["Immediately starting an intense workout program", "Providing education about the benefits of exercise without pressuring them", "Setting a 5-day-per-week training schedule", "Signing them up for a fitness competition"]'::jsonb, 1, 'In Precontemplation, clients are not yet considering change. The best approach is gentle education about exercise benefits, raising awareness, and building rapport without pressure or demanding commitment.', 'medium'),
(16, 'Extrinsic motivation comes from:', '["Personal enjoyment of the activity", "External rewards or pressures such as appearance or social approval", "An innate desire for self-improvement", "Flow state during exercise"]'::jsonb, 1, 'Extrinsic motivation is driven by external factors such as rewards, recognition, social pressure, or avoiding negative consequences. While effective short-term, building intrinsic motivation leads to longer adherence.', 'easy'),
(16, 'A client who has maintained a consistent exercise routine for over one year is in which stage of change?', '["Action", "Maintenance", "Termination", "Preparation"]'::jsonb, 1, 'The Maintenance stage begins after 6 months of consistent behavior change. A client exercising regularly for over a year is solidly in Maintenance, working to prevent relapse.', 'easy'),
(16, 'Which of the following is an example of a SMART goal?', '["I want to get fit this year", "I will lose 10 pounds of body fat in 12 weeks by exercising 4 days per week and following a nutrition plan", "I want to be stronger", "I will exercise more often"]'::jsonb, 1, 'This goal is Specific (lose 10 lbs of fat), Measurable (10 lbs), Attainable/Realistic (12 weeks, 4 days/week with nutrition), and Time-bound (12 weeks). The other options are vague and unmeasurable.', 'medium'),
(16, 'Cognitive distortions such as ''all-or-nothing'' thinking in a fitness context might look like:', '["''I''ll try to exercise three times this week''", "''I missed Monday''s workout, so the whole week is ruined and I might as well quit''", "''I''ll adjust my plan and train tomorrow instead''", "''Some exercise is better than none''"]'::jsonb, 1, 'All-or-nothing thinking is a cognitive distortion where a person sees things in black and white. Missing one session becomes total failure. Trainers can help reframe this by emphasizing progress over perfection.', 'hard'),
(17, 'When training youth clients (ages 6-13), the primary focus should be on:', '["Maximal strength development", "Fun, fundamental movement skills, and proper technique", "Bodybuilding-style hypertrophy programs", "High-intensity interval training"]'::jsonb, 1, 'Youth training should emphasize enjoyment, fundamental movement skills, coordination, and proper exercise technique. Heavy loading and advanced training methods are not appropriate for this developmental stage.', 'easy'),
(17, 'For a pregnant client in her second trimester with no complications, which exercise modification is recommended?', '["Continue training at pre-pregnancy intensity", "Avoid supine (lying face-up) exercises after the first trimester", "Only perform seated exercises", "Stop all exercise until after delivery"]'::jsonb, 1, 'After the first trimester, supine exercises should be avoided because the weight of the uterus can compress the vena cava, reducing blood flow to the heart and fetus. Standing, seated, or side-lying positions are safer alternatives.', 'medium'),
(17, 'Sarcopenia refers to:', '["Excessive joint flexibility in young athletes", "Age-related loss of muscle mass and strength", "A type of bone disease", "Increased fat storage during pregnancy"]'::jsonb, 1, 'Sarcopenia is the age-related progressive loss of muscle mass, strength, and function. Resistance training is one of the most effective interventions to slow or reverse sarcopenia in older adults.', 'easy'),
(17, 'An obese client (BMI > 30) beginning an exercise program should:', '["Start with high-impact plyometrics", "Begin with low-impact, moderate-intensity activities and progress gradually", "Immediately train 6 days per week", "Focus exclusively on maximal strength"]'::jsonb, 1, 'Obese clients should begin with low-impact activities (walking, cycling, swimming) at moderate intensity to reduce joint stress and injury risk. Gradual progression in frequency, duration, and intensity is essential.', 'easy'),
(17, 'Which is a key consideration when training older adults (65+)?', '["They cannot benefit from resistance training", "Balance and fall prevention exercises should be prioritized", "Only stretching is appropriate", "High-intensity plyometrics are the best option"]'::jsonb, 1, 'Older adults are at increased risk for falls and fractures. Balance training, along with resistance and flexibility exercises, should be prioritized to improve stability, bone density, and functional independence.', 'easy'),
(17, 'A 70-year-old client with physician clearance wants to start resistance training. An appropriate starting point would be:', '["Phase 4 maximal strength training", "Phase 1 stabilization endurance with light loads and higher reps", "Olympic lifting program", "Competitive powerlifting routine"]'::jsonb, 1, 'Older adults should begin in Phase 1 (Stabilization Endurance) with light loads, higher reps, and controlled tempos to build neuromuscular control, joint stability, and movement confidence before progressing.', 'medium'),
(17, 'During pregnancy, which of the following is a warning sign to stop exercise immediately?', '["Mild fatigue", "Slight increase in heart rate", "Vaginal bleeding or fluid leakage", "Feeling warm during exercise"]'::jsonb, 2, 'Vaginal bleeding, fluid leakage, dizziness, chest pain, calf swelling, and preterm labor symptoms are absolute contraindications requiring immediate cessation of exercise and medical evaluation.', 'medium'),
(17, 'Resistance training in youth has been shown to:', '["Stunt growth", "Improve strength, bone density, and self-esteem when properly supervised", "Be unsafe under all circumstances", "Only benefit children over 16"]'::jsonb, 1, 'When properly designed and supervised, resistance training is safe and beneficial for youth. It can improve strength, bone density, body composition, motor performance, and psychological well-being.', 'medium'),
(17, 'A postnatal client cleared by her physician to exercise should initially focus on:', '["Heavy barbell squats", "Restoring core and pelvic floor stability", "High-intensity sprint training", "Training for a marathon"]'::jsonb, 1, 'Postnatal clients should prioritize rebuilding core and pelvic floor strength, which are compromised during pregnancy and delivery. Low-intensity stabilization exercises are the appropriate starting point.', 'medium'),
(17, 'Which of the following exercises should be AVOIDED for an obese client with knee pain?', '["Seated leg press", "Deep jump squats", "Recumbent cycling", "Aquatic walking"]'::jsonb, 1, 'Deep jump squats place excessive stress on the knee joints and are high-impact. For an obese client with knee pain, low-impact alternatives like cycling, aquatic exercise, or machine-based movements are more appropriate.', 'easy'),
(18, 'For a client with controlled hypertension, which exercise guideline is most important?', '["Always train to muscular failure", "Avoid the Valsalva maneuver and monitor blood pressure", "Use maximal loads to build strength quickly", "Only perform isometric exercises"]'::jsonb, 1, 'Clients with hypertension should avoid the Valsalva maneuver (holding breath during exertion) as it causes dangerous spikes in blood pressure. Continuous breathing and moderate intensities are essential.', 'medium'),
(18, 'A client with Type 2 diabetes should be monitored for which condition during exercise?', '["Hyperflexibility", "Hypoglycemia (low blood sugar)", "Excessive muscle growth", "Elevated flexibility"]'::jsonb, 1, 'Exercise increases glucose uptake by muscles. Clients with Type 2 diabetes, especially those on insulin or oral medications, are at risk of hypoglycemia during and after exercise. Blood glucose should be monitored.', 'medium'),
(18, 'Osteoporosis is characterized by:', '["Excessive bone density", "Decreased bone density and increased fracture risk", "Inflammation of the joints", "Muscle wasting"]'::jsonb, 1, 'Osteoporosis involves a decrease in bone mineral density, making bones porous and fragile with increased fracture risk. Weight-bearing and resistance exercises help maintain and potentially improve bone density.', 'easy'),
(18, 'Which type of exercise is MOST beneficial for improving bone density in a client with osteoporosis?', '["Swimming", "Weight-bearing and resistance exercise", "Seated stretching only", "Aqua aerobics"]'::jsonb, 1, 'Weight-bearing exercises (walking, jogging) and resistance training apply mechanical stress to bones, stimulating bone remodeling and increasing density. Non-weight-bearing exercises like swimming, while beneficial cardiovascularly, are less effective for bone health.', 'medium'),
(18, 'A client with coronary artery disease has been cleared for exercise. Which guideline should the trainer follow?', '["Begin with maximal exertion testing", "Use moderate intensity (40-80% HRR), monitor for signs and symptoms, and follow physician guidelines", "Avoid all cardiovascular exercise", "Train only with heavy resistance"]'::jsonb, 1, 'Clients with coronary artery disease should train at moderate, physician-recommended intensities while being monitored for symptoms such as chest pain, dizziness, or unusual shortness of breath.', 'medium'),
(18, 'A client with diabetes arrives for a session and reports their blood glucose is 70 mg/dL. The trainer should:', '["Begin the workout as planned", "Have the client consume a fast-acting carbohydrate and recheck before exercising", "Increase exercise intensity to use more glucose", "Send the client home without exercise"]'::jsonb, 1, 'Blood glucose below 100 mg/dL before exercise increases hypoglycemia risk. The client should consume 15-20g of fast-acting carbohydrate, wait 15 minutes, and recheck. Exercise should not begin until glucose is in a safe range.', 'hard'),
(18, 'For a client with osteoporosis, which exercise should be AVOIDED?', '["Standing dumbbell press", "Walking lunges", "Loaded spinal flexion exercises like weighted sit-ups", "Wall push-ups"]'::jsonb, 2, 'Loaded spinal flexion (bending forward under load) significantly increases fracture risk in the vertebrae of clients with osteoporosis. Exercises that maintain a neutral spine are safer.', 'hard'),
(18, 'Regular exercise has been shown to help manage hypertension by:', '["Permanently eliminating the need for medication", "Reducing resting blood pressure by approximately 5-7 mmHg", "Increasing peripheral vascular resistance", "Raising resting heart rate"]'::jsonb, 1, 'Regular aerobic exercise can reduce systolic blood pressure by approximately 5-7 mmHg in individuals with hypertension. While beneficial, exercise may complement but does not necessarily replace medication.', 'medium'),
(18, 'Which is an absolute contraindication to exercise?', '["Controlled Type 2 diabetes", "Mild obesity", "Unstable angina or uncontrolled cardiac arrhythmias", "Mild hypertension managed with medication"]'::jsonb, 2, 'Unstable angina and uncontrolled cardiac arrhythmias are absolute contraindications to exercise, meaning exercise should NOT be performed until the condition is medically stabilized.', 'medium'),
(18, 'A client with asthma should be advised to:', '["Avoid all exercise", "Carry their rescue inhaler and perform a gradual warm-up before exercise", "Only exercise outdoors in cold weather", "Skip the warm-up to save time for training"]'::jsonb, 1, 'Clients with asthma should always have their rescue inhaler accessible. A proper warm-up (10-15 minutes) can reduce the likelihood of exercise-induced bronchoconstriction. Cold, dry air may trigger symptoms.', 'easy'),
(19, 'A personal trainer''s scope of practice INCLUDES:', '["Diagnosing injuries", "Prescribing specific diets for medical conditions", "Designing exercise programs and providing general wellness information", "Recommending clients stop taking prescribed medications"]'::jsonb, 2, 'Personal trainers are qualified to design exercise programs, provide general wellness and nutritional guidance, and motivate clients. Diagnosing injuries, prescribing medical diets, or making medication recommendations falls outside their scope.', 'easy'),
(19, 'A client tells their trainer they have been experiencing sharp chest pain during exercise. The trainer should:', '["Continue the session at a lower intensity", "Diagnose the issue and modify exercises accordingly", "Stop the session and refer the client to a medical professional immediately", "Ignore it if the client wants to continue"]'::jsonb, 2, 'Chest pain during exercise is a potential medical emergency. The trainer should stop the session immediately and refer the client to a medical professional. Continuing exercise could be life-threatening.', 'easy'),
(19, 'Professional liability insurance protects a personal trainer against:', '["Loss of personal property", "Claims of negligence or injury arising from professional services", "Losing clients to competitors", "Equipment malfunction at a gym"]'::jsonb, 1, 'Professional liability (malpractice) insurance protects trainers against legal claims alleging negligence, injury, or harm resulting from their professional services and advice.', 'easy'),
(19, 'An informed consent form serves to:', '["Replace the need for a PAR-Q", "Ensure the client understands the risks of exercise and agrees to participate", "Eliminate all legal liability for the trainer", "Diagnose pre-existing conditions"]'::jsonb, 1, 'An informed consent form documents that the client has been educated about the potential risks and benefits of exercise and voluntarily agrees to participate. It does not eliminate all liability.', 'medium'),
(19, 'A trainer observes another trainer at their gym performing exercises with a client that appear unsafe. The most professional course of action is:', '["Post about it on social media", "Confront the other trainer in front of their client", "Report the concern to the fitness manager or supervisor privately", "Ignore it because it''s not their client"]'::jsonb, 2, 'Professional conduct requires addressing safety concerns through proper channels. Reporting to a supervisor privately protects client safety while maintaining professional respect and appropriate boundaries.', 'medium'),
(19, 'Which document should a new client complete BEFORE starting any exercise program?', '["A workout journal", "A Physical Activity Readiness Questionnaire (PAR-Q) and health history form", "A supplement order form", "A body composition goal sheet only"]'::jsonb, 1, 'The PAR-Q and health history form help identify contraindications, risk factors, and medical conditions that may require physician clearance before exercise. This is a mandatory pre-participation step.', 'easy'),
(19, 'Client confidentiality means a trainer should:', '["Share client progress photos on social media without permission", "Discuss a client''s health conditions with other trainers casually", "Protect all personal health and fitness information and only share with written consent", "Only keep records for one week"]'::jsonb, 2, 'Client confidentiality requires protecting all personal health information. Sharing any details requires written consent from the client. This builds trust and is a legal and ethical obligation.', 'easy'),
(19, 'A personal trainer who provides a specific meal plan for a client with Crohn''s disease is:', '["Demonstrating advanced knowledge", "Operating outside their scope of practice", "Following best practices", "Meeting the client''s needs appropriately"]'::jsonb, 1, 'Providing specific meal plans for medical conditions like Crohn''s disease is medical nutrition therapy, which requires a registered dietitian or other qualified healthcare provider. This is outside a trainer''s scope of practice.', 'medium'),
(19, 'Maintaining current CPR/AED certification is:', '["Optional for certified personal trainers", "Required by most certification organizations and facilities", "Only needed for trainers working with seniors", "Not related to scope of practice"]'::jsonb, 1, 'Current CPR/AED certification is required by NASM and most fitness facilities. Trainers must be prepared to respond to cardiac emergencies, and keeping this certification current is a professional obligation.', 'easy'),
(19, 'A trainer develops a romantic relationship with a current client. This is considered:', '["Acceptable if both parties agree", "A violation of professional boundaries and ethical guidelines", "Normal in the fitness industry", "Acceptable with written consent"]'::jsonb, 1, 'Romantic relationships with current clients violate professional boundaries and ethical guidelines. The power dynamic between trainer and client can compromise professional judgment, safety, and the client''s best interests.', 'medium'),
(20, 'Client retention is MOST influenced by:', '["Offering the lowest prices", "Building rapport, delivering results, and providing a positive experience", "Having the newest equipment", "Training every client the same way"]'::jsonb, 1, 'Client retention is driven by the relationship between trainer and client, consistent results, and positive training experiences. Personalization, communication, and genuine care are more influential than price alone.', 'easy'),
(20, 'During a sales consultation, a prospective client says, ''I''m not sure I can afford personal training.'' The best response is:', '["Offer to train them for free", "Ignore the objection and push for a sale", "Acknowledge the concern, discuss the value and investment in their health, and explore flexible options", "Tell them they can''t afford NOT to train"]'::jsonb, 2, 'Handling price objections effectively involves acknowledging the concern empathetically, reframing the cost as an investment in health, and presenting flexible payment or package options that fit their budget.', 'medium'),
(20, 'The most effective way to generate new personal training clients is through:', '["Cold calling random people", "Referrals from satisfied current clients", "Posting flyers only", "Waiting for clients to approach you"]'::jsonb, 1, 'Referrals from satisfied clients are the most effective and cost-efficient way to generate new business. Happy clients become advocates and provide credible, trust-based recommendations.', 'easy'),
(20, 'A personal trainer''s ''elevator pitch'' should:', '["Be 10 minutes long and highly detailed", "Concisely communicate who they help, what problem they solve, and the results they deliver in under 60 seconds", "Only include pricing information", "Focus entirely on their certifications and credentials"]'::jsonb, 1, 'An elevator pitch is a brief, compelling introduction that communicates your value proposition — who you help, what problem you solve, and the outcomes you deliver — in approximately 30-60 seconds.', 'medium'),
(20, 'Which of the following is a key component of a successful first session with a new client?', '["Pushing them to complete failure to show your training style", "Building rapport, reviewing goals, conducting assessments, and creating a positive experience", "Spending the entire session on paperwork", "Showing them every machine in the gym"]'::jsonb, 1, 'The first session should build rapport, review goals, conduct initial assessments, introduce basic exercises with proper form, and create an overall positive experience that motivates the client to return.', 'easy'),
(20, 'Net promoter score (NPS) in a fitness business context measures:', '["Monthly revenue", "How likely clients are to recommend your services to others", "The number of new memberships sold", "Total social media followers"]'::jsonb, 1, 'Net Promoter Score measures customer loyalty by asking how likely someone is to recommend your services. High NPS indicates strong client satisfaction and predicts referral-based growth.', 'hard'),
(20, 'A personal trainer who tracks session completion rates, renewal rates, and client outcomes is practicing:', '["Micromanagement", "Evidence-based business management using key performance indicators (KPIs)", "Unnecessary administrative work", "Obsessive behavior"]'::jsonb, 1, 'Tracking KPIs like session completion rates, renewal rates, and client outcomes allows trainers to evaluate business health, identify areas for improvement, and make data-driven decisions.', 'medium'),
(20, 'Social media marketing for personal trainers is most effective when:', '["Posting only selfies and personal content", "Providing consistent value through educational content, client success stories, and genuine engagement", "Buying followers to appear popular", "Posting once per year"]'::jsonb, 1, 'Effective social media marketing provides value through educational content, demonstrates expertise, shares authentic client success stories, and builds genuine community engagement.', 'easy'),
(20, 'During a client consultation, ''active listening'' involves:', '["Planning your response while the client speaks", "Focusing on the sale rather than the client''s needs", "Giving full attention, asking clarifying questions, and reflecting back what was heard", "Interrupting to share your expertise"]'::jsonb, 2, 'Active listening requires full attention to the speaker, asking clarifying questions to deepen understanding, and reflecting or paraphrasing to confirm comprehension. It builds trust and helps identify true client needs.', 'easy'),
(20, 'A trainer who offers a free introductory session is using which marketing strategy?', '["Loss leader / trial offer", "Bait and switch", "Hard selling", "Price gouging"]'::jsonb, 0, 'A free introductory session is a loss leader or trial offer strategy. It allows potential clients to experience the trainer''s service with no risk, building trust and demonstrating value before asking for commitment.', 'medium'),
(20, 'Which approach is MOST effective for handling a client who is considering canceling their training package?', '["Let them cancel without discussion", "Guilt-trip them into staying", "Have an open conversation to understand their concerns, address objections, and explore solutions", "Offer a full refund immediately"]'::jsonb, 2, 'Open communication helps uncover the real reasons behind cancellation. Understanding concerns (financial, scheduling, results) allows the trainer to collaboratively find solutions and demonstrate ongoing value.', 'medium');
